import time
import anthropic

def profile_parallel_tools(tools):
    start_times = {tool.name: time.time() for tool in tools}
    results = client.tools.call_many(
        tools=[{'name': name, 'input': {}} for name in start_times],
        tool_choice='any'
    )
    latencies = {
        result.tool_use.id: time.time() - start_times[result.tool_use.name]
        for result in results
    }
    max_latency = max(latencies.values())
    return max_latency > 10.0  # Alert on >10s tools

