import asyncio

async def selective_parallel_tools(tools, terminate_early=True):
    tasks = {tool.name: asyncio.create_task(call_single_tool(tool)) for tool in tools}

    completed = {}
    for done_task in asyncio.as_completed(tasks.values()):
        result = await done_task
        completed[result.tool_name] = result

        if terminate_early and is_sufficient_data(result):
            # Cancel remaining
            for task in tasks.values():
                if not task.done():
                    task.cancel()
            break
    return completed

